interface GameSelectorGridProps {
  counts?: Record<string, number>
}

export function GameSelectorGrid({ counts }: GameSelectorGridProps) {
  return (
    <section className="px-5 py-[40px] sm:px-12 sm:py-[64px]">
      <div className="mx-auto max-w-[1344px]">
        <p className="mb-7 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow">
          Shop by Game
        </p>
        <div className="grid grid-cols-2 gap-3 md:grid-cols-4 md:gap-4">
          {GAMES.map((game) => (
            <GameTile
              key={game.code}
              code={game.code}
              display={game.display}
              image={game.image}
              bgGradient={game.bgGradient}
              overlayGradient={game.overlayGradient}
              count={counts?.[game.code]}
            />
          ))}
        </div>
      </div>
    </section>
  )
}

"use client"

import Link from "next/link"

interface GameTileProps {
  code: string
  display: string
  image: string
  bgGradient: string
  overlayGradient: string
  count?: number
}

export function GameTile({
  code,
  display,
  image,
  bgGradient,
  overlayGradient,
  count,
}: GameTileProps) {
  function handleClick() {
    try {
      const secure = location.protocol === "https:" ? "; Secure" : ""
      document.cookie = `sd_game_pref=${encodeURIComponent(code)}; max-age=2592000; path=/; SameSite=Lax${secure}`
    } catch {
      // Best-effort — navigation fires regardless
    }
  }

  const ariaLabel =
    count !== undefined ? `${display} — ${count.toLocaleString()} cards` : display

  return (
    <Link
      href={`/cards?game=${encodeURIComponent(code)}`}
      aria-label={ariaLabel}
      onClick={handleClick}
      className="group relative block cursor-pointer overflow-hidden rounded-2xl transition-all duration-200 [@media(pointer:fine)]:hover:scale-[1.02] [@media(pointer:fine)]:hover:shadow-[0_8px_40px_rgba(0,0,0,0.4)] active:scale-[0.98] focus-visible:outline-2 focus-visible:outline-accent focus-visible:outline-offset-2"
      style={{ aspectRatio: "16 / 10" }}
    >
      {/* Gradient background */}
      <div
        className="absolute inset-0"
        style={{ background: bgGradient }}
      >
        {/* Pattern decoration */}
        <div
          className="absolute inset-0"
          style={{
            backgroundImage:
              "radial-gradient(circle at 30% 30%, rgba(255,255,255,0.03) 0%, transparent 60%), radial-gradient(circle at 70% 60%, rgba(255,255,255,0.02) 0%, transparent 50%)",
          }}
        />
      </div>

      {/* Card-back image background */}
      <div
        className="absolute inset-0 bg-cover bg-center bg-no-repeat opacity-40"
        style={{ backgroundImage: `url(${image})` }}
      />

      {/* Game-colour overlay */}
      <div
        className="absolute inset-0 flex flex-col justify-end p-4 md:p-6"
        style={{ background: overlayGradient }}
      >
        <span className="font-barlow-condensed text-base font-bold text-white md:text-[22px]">
          {display}
        </span>
        {count !== undefined && (
          <span
            data-testid="tile-count"
            className="font-dm-mono text-[11px] text-white/70 md:text-xs"
          >
            {count.toLocaleString()} cards
          </span>
        )}
      </div>
    </Link>
  )
}

interface TrustSectionProps {
  cardCount: string
}

const TRUST_CARDS = [
  {
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <rect width="18" height="18" x="3" y="3" rx="2" />
        <path d="M7 7h10" />
        <path d="M7 12h10" />
        <path d="M7 17h10" />
      </svg>
    ),
    valueKey: "cardCount" as const,
    valueSuffix: "+",
    label: "Cards across 4 games, updated daily",
  },
  {
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10" />
        <path d="m9 12 2 2 4-4" />
      </svg>
    ),
    staticValue: "Verified Sellers",
    label: "Every seller reviewed and graded",
  },
  {
    icon: (
      <svg viewBox="0 0 24 24" fill="none" stroke="currentColor" strokeWidth="2" strokeLinecap="round" strokeLinejoin="round">
        <path d="M12 22s8-4 8-10V5l-8-3-8 3v7c0 6 8 10 8 10" />
      </svg>
    ),
    staticValue: "Buyer Protection",
    label: "Every transaction covered",
  },
]

export function TrustSection({ cardCount }: TrustSectionProps) {
  return (
    <section aria-label="Why SideDecked" className="px-5 py-[40px] sm:px-12 sm:py-[64px]">
      <div className="mx-auto max-w-[1344px]">
        <p className="mb-7 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow">
          Why SideDecked
        </p>
        <div className="grid gap-3 sm:gap-4 lg:grid-cols-3">
          {TRUST_CARDS.map((card, i) => {
            const value =
              card.valueKey === "cardCount"
                ? `${cardCount}${card.valueSuffix ?? ""}`
                : card.staticValue

            return (
              <div
                key={i}
                className="relative overflow-hidden rounded-2xl border border-border p-[24px] px-5 text-center sm:p-[36px] sm:px-7"
                style={{
                  background: "rgba(24, 22, 42, 0.40)",
                  backdropFilter: "blur(8px)",
                }}
              >
                {/* Top glow line */}
                <div
                  className="absolute left-1/2 top-0 h-px w-[120px] -translate-x-1/2"
                  style={{
                    background:
                      "linear-gradient(90deg, transparent, var(--brand-primary, #8B5CF6), transparent)",
                  }}
                />

                {/* Icon */}
                <div className="mx-auto mb-4 flex h-12 w-12 items-center justify-center rounded-[14px] border border-primary/15 bg-primary/10 text-primary">
                  <div className="h-[22px] w-[22px]">{card.icon}</div>
                </div>

                {/* Value */}
                <p className="mb-1 font-barlow-condensed text-[26px] font-bold text-primary lg:text-[32px]">
                  {value}
                </p>

                {/* Label */}
                <p className="text-[13px] leading-relaxed text-secondary sm:text-sm">
                  {card.label}
                </p>
              </div>
            )
          })}
        </div>
      </div>
    </section>
  )
}

import Link from "next/link"

interface SellerCTABannerProps {
