  return (
    <section aria-label="Start selling" className="px-5 pb-[48px] sm:px-12 sm:pb-[64px]">
      <div
        className="relative mx-auto max-w-[1344px] overflow-hidden rounded-2xl px-6 py-[40px] text-center sm:rounded-[20px] sm:px-12 sm:py-[56px]"
        style={{
          background: "linear-gradient(135deg, var(--brand-primary, #8B5CF6), var(--brand-secondary, #FF7849))",
        }}
      >
        {/* Decorative glow */}
        <div
          className="pointer-events-none absolute -right-[100px] top-0 h-[400px] w-[400px]"
          style={{
            background:
              "radial-gradient(circle, rgba(255,255,255,0.08) 0%, transparent 60%)",
          }}
        />

        <h2 className="relative font-barlow-condensed text-[32px] font-extrabold text-white sm:text-[44px]">
          Join 10,000+ Players
        </h2>
        <p className="relative mb-7 mt-2 text-sm text-white/85 sm:text-base">
          Start selling in minutes. No listing fees.
        </p>
        <Link
          href="/sell"
          className="relative inline-flex items-center rounded-xl bg-white px-8 py-3.5 font-barlow text-[15px] font-bold text-[#18162A] transition-all [@media(pointer:fine)]:hover:-translate-y-0.5 [@media(pointer:fine)]:hover:shadow-[0_8px_32px_rgba(0,0,0,0.2)]"
