  return (
    <section aria-label="Trending cards" data-testid="trending-strip" className="py-[32px] sm:py-[48px]">
      <p className="mb-6 px-5 text-[11px] font-semibold uppercase tracking-[0.12em] text-tertiary font-barlow sm:px-12">
        🔥 Trending Now
